4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty set for empty grid", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	
9	  it("should kill lone cell with no neighbors", () => {
10	    const grid = new Set(["0,0"]);
11	    expect(nextGeneration(grid)).toEqual(new Set());
12	  });
13	
14	  it("should kill cell with one neighbor", () => {
15	    const grid = new Set(["0,0", "1,0"]);
16	    expect(nextGeneration(grid)).toEqual(new Set());
17	  });
18	
19	  it("should keep cell alive with exactly two neighbors", () => {
20	    const grid = new Set(["0,0", "1,0", "0,1"]);
21	    expect(nextGeneration(grid)).toEqual(new Set(["0,0"]));
22	  });
23	
24	  it("should keep cell alive with exactly three neighbors", () => {
25	    const grid = new Set(["0,0", "1,0", "0,1", "1,1"]);
26	    expect(nextGeneration(grid)).toEqual(new Set(["0,0", "1,0", "0,1", "1,1"]));
27	  });
28	
